use crate::types::{DecideInput, DecideOutput};

// Fixed-precision real comparison per spec (six most significant digits).
fn realcompare(a: f64, b: f64) -> &'static str {
    // Relative tolerance based on six significant digits.
    // Treat near-zero carefully: scale by max(1, |a|, |b|).
    let scale = a.abs().max(b.abs()).max(1.0);
    let tol = 1e-6 * scale;
    let diff = (a - b).abs();
    if diff <= tol {
        EQ
    } else if a < b {
        LT
    } else {
        GT
    }
}

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    (dx * dx + dy * dy).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()) * 0.5
}

fn angle_at_vertex(ax: f64, ay: f64, bx: f64, by: f64, cx: f64, cy: f64) -> Option<f64> {
    // Angle ABC at vertex B formed by BA and BC
    let ux = ax - bx;
    let uy = ay - by;
    let vx = cx - bx;
    let vy = cy - by;
    let un = (ux * ux + uy * uy).sqrt();
    let vn = (vx * vx + vy * vy).sqrt();
    if realcompare(un, 0.0) == EQ || realcompare(vn, 0.0) == EQ {
        return None;
    }
    let dot = ux * vx + uy * vy;
    let cosang = (dot / (un * vn)).clamp(-1.0, 1.0);
    Some(cosang.acos())
}

fn point_line_distance(px: f64, py: f64, ax: f64, ay: f64, bx: f64, by: f64) -> f64 {
    // Distance from point P to the infinite line through A and B.
    let abx = bx - ax;
    let aby = by - ay;
    if realcompare(dist(ax, ay, bx, by), 0.0) == EQ {
        // A and B coincide: distance to the point.
        return dist(px, py, ax, ay);
    }
    let num = ((px - ax) * aby - (py - ay) * abx).abs();
    let den = (abx * abx + aby * aby).sqrt();
    num / den
}

fn minimal_enclosing_circle_radius_for_three(
    x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64,
) -> f64 {
    // If points are colinear (area ~ 0), radius is half the max pair distance.
    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    if realcompare(area, 0.0) == EQ {
        let d12 = dist(x1, y1, x2, y2);
        let d23 = dist(x2, y2, x3, y3);
        let d13 = dist(x1, y1, x3, y3);
        return 0.5 * d12.max(d23).max(d13);
    }
    // Otherwise the circumradius: R = (a*b*c)/(4*area) where a=|BC|, b=|CA|, c=|AB|.
    let a = dist(x2, y2, x3, y3);
    let b = dist(x3, y3, x1, y1);
    let c = dist(x1, y1, x2, y2);
    (a * b * c) / (4.0 * area)
}

fn quadrant(x: f64, y: f64) -> u8 {
    // Priority by quadrant number when on axes (I over II over III over IV).
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x <= 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let n = input.numpoints;
    let p = &input.parameters;

    let mut cmv = vec![false; 15];

    // Helper closure to access coordinates by index.
    let xy = |i: usize| -> (f64, f64) { (input.x[i], input.y[i]) };

    // LIC 1: two consecutive points farther than LENGTH1.
    cmv[0] = {
        let mut ok = false;
        for i in 0..(n.saturating_sub(1)) {
            let (x1, y1) = xy(i);
            let (x2, y2) = xy(i + 1);
            if realcompare(dist(x1, y1, x2, y2), p.length1) == GT { ok = true; break; }
        }
        ok
    };

    // LIC 2: three consecutive points cannot fit in/on a circle of radius RADIUS1.
    cmv[1] = {
        let mut ok = false;
        if n >= 3 {
            for i in 0..(n - 2) {
                let (x1, y1) = xy(i);
                let (x2, y2) = xy(i + 1);
                let (x3, y3) = xy(i + 2);
                let r = minimal_enclosing_circle_radius_for_three(x1, y1, x2, y2, x3, y3);
                if realcompare(r, p.radius1) == GT { ok = true; break; }
            }
        }
        ok
    };

    // LIC 3: angle condition on three consecutive points, vertex at middle.
    cmv[2] = {
        let mut ok = false;
        if n >= 3 {
            let pi = std::f64::consts::PI;
            for i in 0..(n - 2) {
                let (a, b, c) = (i, i + 1, i + 2);
                let (x1, y1) = xy(a);
                let (x2, y2) = xy(b);
                let (x3, y3) = xy(c);
                if let Some(ang) = angle_at_vertex(x1, y1, x2, y2, x3, y3) {
                    if realcompare(ang, pi - p.epsilon) == LT || realcompare(ang, pi + p.epsilon) == GT {
                        ok = true; break;
                    }
                }
            }
        }
        ok
    };

    // LIC 4: triangle area of three consecutive points greater than AREA1.
    cmv[3] = {
        let mut ok = false;
        if n >= 3 {
            for i in 0..(n - 2) {
                let (x1, y1) = xy(i);
                let (x2, y2) = xy(i + 1);
                let (x3, y3) = xy(i + 2);
                let a = triangle_area(x1, y1, x2, y2, x3, y3);
                if realcompare(a, p.area1) == GT { ok = true; break; }
            }
        }
        ok
    };

    // LIC 5: Q_PTS consecutive points occupy more than QUADS quadrants.
    cmv[4] = {
        let mut ok = false;
        let q = p.q_pts;
        let qu = p.quads;
        if q >= 2 && q <= n {
            for i in 0..=(n - q) {
                let mut seen = [false; 5]; // 1..=4 used
                let mut count = 0usize;
                for j in i..(i + q) {
                    let (x, y) = xy(j);
                    let qn = quadrant(x, y) as usize;
                    if !seen[qn] { seen[qn] = true; count += 1; }
                }
                if count > qu { ok = true; break; }
            }
        }
        ok
    };

    // LIC 6: exists two consecutive points with decreasing X.
    cmv[5] = {
        let mut ok = false;
        if n >= 2 {
            for i in 0..(n - 1) {
                if realcompare(input.x[i + 1] - input.x[i], 0.0) == LT { ok = true; break; }
            }
        }
        ok
    };

    // LIC 7: Among N_PTS consecutive points, at least one farther than DIST from line through first and last.
    cmv[6] = {
        let mut ok = false;
        let m = p.n_pts;
        if n >= 3 && m >= 3 && m <= n {
            for i in 0..=(n - m) {
                let (ax, ay) = xy(i);
                let (bx, by) = xy(i + m - 1);
                for j in i..(i + m) {
                    let (px, py) = xy(j);
                    let d = point_line_distance(px, py, ax, ay, bx, by);
                    if realcompare(d, p.dist) == GT { ok = true; break; }
                }
                if ok { break; }
            }
        }
        ok
    };

    // LIC 8: two points with exactly K_PTS intervening, distance > LENGTH1.
    cmv[7] = {
        let mut ok = false;
        if n >= 3 {
            let k = p.k_pts;
            if k + 2 <= n {
                for i in 0..=(n - k - 2) {
                    let j = i + k + 1;
                    let (x1, y1) = xy(i);
                    let (x2, y2) = xy(j);
                    if realcompare(dist(x1, y1, x2, y2), p.length1) == GT { ok = true; break; }
                }
            }
        }
        ok
    };

    // LIC 9: three points with A_PTS and B_PTS intervening cannot fit in/on circle radius RADIUS1.
    cmv[8] = {
        let mut ok = false;
        if n >= 5 {
            let a_pts = p.a_pts;
            let b_pts = p.b_pts;
            if a_pts + b_pts + 3 <= n {
                for i in 0..=(n - (a_pts + b_pts + 3)) {
                    let j = i + a_pts + 1;
                    let k = j + b_pts + 1;
                    let (x1, y1) = xy(i);
                    let (x2, y2) = xy(j);
                    let (x3, y3) = xy(k);
                    let r = minimal_enclosing_circle_radius_for_three(x1, y1, x2, y2, x3, y3);
                    if realcompare(r, p.radius1) == GT { ok = true; break; }
                }
            }
        }
        ok
    };

    // LIC 10: three points with C_PTS and D_PTS intervening form extreme angle at middle.
    cmv[9] = {
        let mut ok = false;
        if n >= 5 {
            let c_pts = p.c_pts;
            let d_pts = p.d_pts;
            if c_pts + d_pts + 3 <= n {
                let pi = std::f64::consts::PI;
                for i in 0..=(n - (c_pts + d_pts + 3)) {
                    let j = i + c_pts + 1;
                    let k = j + d_pts + 1;
                    let (x1, y1) = xy(i);
                    let (x2, y2) = xy(j);
                    let (x3, y3) = xy(k);
                    if let Some(ang) = angle_at_vertex(x1, y1, x2, y2, x3, y3) {
                        if realcompare(ang, pi - p.epsilon) == LT || realcompare(ang, pi + p.epsilon) == GT {
                            ok = true; break;
                        }
                    }
                }
            }
        }
        ok
    };

    // LIC 11: three points with E_PTS and F_PTS intervening, area > AREA1.
    cmv[10] = {
        let mut ok = false;
        if n >= 5 {
            let e_pts = p.e_pts;
            let f_pts = p.f_pts;
            if e_pts + f_pts + 3 <= n {
                for i in 0..=(n - (e_pts + f_pts + 3)) {
                    let j = i + e_pts + 1;
                    let k = j + f_pts + 1;
                    let (x1, y1) = xy(i);
                    let (x2, y2) = xy(j);
                    let (x3, y3) = xy(k);
                    let a = triangle_area(x1, y1, x2, y2, x3, y3);
                    if realcompare(a, p.area1) == GT { ok = true; break; }
                }
            }
        }
        ok
    };

    // LIC 12: two points with exactly G_PTS intervening, decreasing X.
    cmv[11] = {
        let mut ok = false;
        if n >= 3 {
            let g = p.g_pts;
            if g + 2 <= n {
                for i in 0..=(n - g - 2) {
                    let j = i + g + 1;
                    if realcompare(input.x[j] - input.x[i], 0.0) == LT { ok = true; break; }
                }
            }
        }
        ok
    };

    // LIC 13: > LENGTH1 with K_PTS intervening AND < LENGTH2 with K_PTS intervening.
    cmv[12] = {
        let mut part1 = false;
        let mut part2 = false;
        if n >= 3 {
            let k = p.k_pts;
            if k + 2 <= n {
                for i in 0..=(n - k - 2) {
                    let j = i + k + 1;
                    let (x1, y1) = xy(i);
                    let (x2, y2) = xy(j);
                    let d = dist(x1, y1, x2, y2);
                    if !part1 && realcompare(d, p.length1) == GT { part1 = true; }
                    if !part2 && realcompare(d, p.length2) == LT { part2 = true; }
                    if part1 && part2 { break; }
                }
            }
        }
        part1 && part2
    };

    // LIC 14: cannot fit in RADIUS1 AND can fit in RADIUS2 with A_PTS/B_PTS separation.
    cmv[13] = {
        let mut part1 = false;
        let mut part2 = false;
        if n >= 5 {
            let a_pts = p.a_pts;
            let b_pts = p.b_pts;
            if a_pts + b_pts + 3 <= n {
                for i in 0..=(n - (a_pts + b_pts + 3)) {
                    let j = i + a_pts + 1;
                    let k = j + b_pts + 1;
                    let (x1, y1) = xy(i);
                    let (x2, y2) = xy(j);
                    let (x3, y3) = xy(k);
                    let r = minimal_enclosing_circle_radius_for_three(x1, y1, x2, y2, x3, y3);
                    if !part1 && realcompare(r, p.radius1) == GT { part1 = true; }
                    if !part2 && (realcompare(r, p.radius2) == LT || realcompare(r, p.radius2) == EQ) { part2 = true; }
                    if part1 && part2 { break; }
                }
            }
        }
        part1 && part2
    };

    // LIC 15: area > AREA1 AND area < AREA2 with E_PTS/F_PTS separation.
    cmv[14] = {
        let mut part1 = false;
        let mut part2 = false;
        if n >= 5 {
            let e_pts = p.e_pts;
            let f_pts = p.f_pts;
            if e_pts + f_pts + 3 <= n {
                for i in 0..=(n - (e_pts + f_pts + 3)) {
                    let j = i + e_pts + 1;
                    let k = j + f_pts + 1;
                    let (x1, y1) = xy(i);
                    let (x2, y2) = xy(j);
                    let (x3, y3) = xy(k);
                    let a = triangle_area(x1, y1, x2, y2, x3, y3);
                    if !part1 && realcompare(a, p.area1) == GT { part1 = true; }
                    if !part2 && realcompare(a, p.area2) == LT { part2 = true; }
                    if part1 && part2 { break; }
                }
            }
        }
        part1 && part2
    };

    // Build PUM. Diagonal from input.pum_diag; off-diagonals from LCM and CMV.
    let mut pum = vec![vec![true; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                let conn = &input.lcm[i][j];
                pum[i][j] = match conn.as_str() {
                    NOTUSED => true,
                    ANDD => cmv[i] && cmv[j],
                    ORR => cmv[i] || cmv[j],
                    _ => false,
                };
            }
        }
    }

    // Build FUV: true if diagonal is false OR entire row true.
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if pum[i][i] == false {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if !pum[i][j] { all_true = false; break; }
            }
            fuv[i] = all_true;
        }
    }

    let launch = fuv.iter().all(|&b| b);

    DecideOutput { cmv, pum, fuv, launch }
}

#[cfg(test)]
mod tests {
    use super::*;
    #[test]
    fn test_realcompare_basic() {
        assert_eq!(realcompare(1.0, 1.0), EQ);
        assert_eq!(realcompare(1.0 + 1e-12, 1.0), EQ);
        assert_eq!(realcompare(1.000002, 1.0), GT);
        assert_eq!(realcompare(0.999998, 1.0), LT);
    }
}
